    #[test]
    fn test_overlap_carries_heading_hierarchy() {
        let chunker = MarkdownChunker::new();
        let prev = RawChunk {
            content: "## Auth\n\n### JWT\n\nJWT details.".into(),
            chunk_type: "heading_section".into(),
            start_line: 1,
            end_line: 5,
            metadata: ChunkMetadata::default(),
        };
        let next = RawChunk {
            content: "### OAuth\n\nOAuth details.".into(),
            chunk_type: "heading_section".into(),
            start_line: 6,
            end_line: 8,
            metadata: ChunkMetadata::default(),
        };
        let overlap = chunker.overlap_context(&prev, &next);
        // Should carry heading hierarchy as context
        assert!(overlap.is_some(), "markdown overlap should carry heading context");
    }

